#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 uv2 = vUv;
//if(uv2.x >= 0.5) {uv2.x = 1-uv2.x;}
//if(uv2.y >= 0.5) {uv2.y = 1-uv2.y;}

//float1 cs = cos(0.25*3.14159);
//float1 sn = sin(0.25*3.14159);
//vec2 uv3 = uv2;
//uv2.x = uv3.x * cs - uv3.y * sn;
//uv2.y = uv3.x * sn + uv3.y * cs;

vUv.x=uv2.x;
vUv.y=uv2.y;

    // sample previous uFrame
    ret = texture( sampler_main, vUv ).xyz;

    // darken (decay) over uTime
    ret *= 0.7;

float1 a = vUv.x;
float1 b = vUv.y;
float1 ca;
float1 cb;
if(q9 == 5){
    ca = 0.285;
    cb = 0;
}
else if(q9 == 6){
    ca = -0.66176 + 0.03*q20;
    cb = -0.3842;
}
else if(q9 == 0) {
    ca = -0.7269 + 0.01*q21 ;
    cb = 0.1889 + 0.01*q22;
}
else {
    ca = a;
    cb = b;
}
float1 aa;
float1 bb;

float1 n = 0;
float1 maxiter = 60;
float1 m=0;
float1 r = 20;
float1 r2 = r*r;
//float1 dist = length(z);
vec3 col;

float1 pa;
float1 pb;
vec2 z;
vec2 pz;
while(n < maxiter && m==0)
{
    aa = a*a - b*b;
    bb = 2*a*b;
    pa = a;
    pb = b;
    pz = vec2(pa,pb);
    a = aa + ca;
    b = bb + cb;
    z = vec2(a,b);
    //if(sqrt(a*a + b*b) > r2) // no
    //if(sqrt(pow(a-pa,2) + pow(b-pb,2)) > r2)
    //if(dot(z,pz) > r2) // creates the leaves outside the mandelbrot set
    if(sqrt(a*a + b*b) > r2)
    {
        m = 1;
    }
    else
    {
        n++;
    }
}

//col = texture(sampler_colors3, vec2(0.5 + 0.5*sin(n*0.05),0.5 + 0.5*cos(n*0.05+uTime))).xyz;

float1 dist = (sqrt(a*a + b*b));
float1 fraciter = (dist - r) / (r2 - r);
fraciter = log2(log(dist) / log(r));
n -= fraciter; // makes the colors smoother, outside of the mandelbrot set
vec3 color;

color.x = 0.5 + 0.5*sin(0.21*n*3.5 + 0.5*uTime + 0.2*q5);
color.y = 0.5 + 0.5*cos(0.33*n*3.5 + 0.7*uTime + 0.2*q6);
color.z = 0.5 + 0.5*sin(0.45*n*3.5 + 0.9*uTime + 0.2*q7);

if(m == 1)
{
    ret = color;
}
else
{
    //ret.x=0.1;
    //ret.y=0.5;
    //ret.z=0;
    ret=color;
}


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 uv2 = vUv;
if(uv2.x >= 0.5) {uv2.x = 1-uv2.x;}
if(uv2.y >= 0.5) {uv2.y = 1-uv2.y;}

//float1 cs = cos(0.25*3.14159);
//float1 sn = sin(0.25*3.14159);
//vec2 uv3 = uv2;
//uv2.x = uv3.x * cs - uv3.y * sn;
//uv2.y = uv3.x * sn + uv3.y * cs;

vUv.x=uv2.x;
vUv.y=uv2.y;


    vec2 d = uTexSize.zw;
    vec3 dx = ( GetPixel(vUv+vec2(1,0)*d)-GetPixel(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetPixel(vUv+vec2(0,1)*d)-GetPixel(vUv-vec2(0,1)*d) );
vec2 dz = vec2(dx.y,dy.y)*3;

d = uTexSize.zw*2;
dx = ( 2*GetBlur1(vUv+vec2(1,0)*d)-2*GetBlur1(vUv-vec2(1,0)*d) )*0.5;
dy = ( 2*GetBlur1(vUv+vec2(0,1)*d)-2*GetBlur1(vUv-vec2(0,1)*d) )*0.5;

dz +=vec2(dx.y,dy.y);

vec3 bg = pow(length(dz)*2.8+0,0.7) + GetBlur2(vUv).y*0.4-0.1;

ret = bg*vec3(vRadius*4,0.6,.1);
ret = mix(ret,vec3(0.5,0.2,0.1),GetPixel(vUv + vec2(dx.x,dy.x)*uTexSize.zw*18).x*7);
ret = mix(ret,1,GetPixel(vUv).z);

//ret = GetPixel(vUv);
ret /= vec3(1.1,1.1,2.7);
ret /= vec3(-2.8,1.5,1.5);

  fragColor = ret;
}
